const serialize = require('node-serialize');
const cookieParser = require('cookie-parser');

const app = express();
app.use(cookieParser());
app.use(express.json());

// DANGEROUS: Deserializing untrusted user input
app.get('/profile', (req, res) => {
  const sessionCookie = req.cookies.session;

  if (sessionCookie) {
    // VULNERABLE: Deserializing user-controlled data
    const decoded = Buffer.from(sessionCookie, 'base64').toString();
    const sessionData = serialize.unserialize(decoded);

    res.json({
      username: sessionData.username,
      role: sessionData.role,
      lastLogin: sessionData.lastLogin
    });
  } else {
    res.status(401).json({ error: 'No session found' });
  }
});

app.post('/login', (req, res) => {
  const { username, password } = req.body;

  // Simplified auth for demo
  if (username && password) {
    const sessionData = {
      username: username,
      role: 'user',
      lastLogin: new Date().toISOString()
    };

    // Serialize and set as cookie
    const serialized = serialize.serialize(sessionData);
